  ?silverTeam wdt:P332 wd:Q323462.
  ?silverTeam wdt:P1334 wd:Q61056311.
  ?silverTeam rdfs:label ?silverTeamLabel.
  FILTER(LANGMATCHES(LANG(?silverTeamLabel), 'en'))
}

